import React, { useState, useEffect } from 'react';

function Marketplace() {
  const [list, setList] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // बॅकएंडकडून डेटा मागवणे
    fetch('http://localhost:3000/api/get')
      .then(res => {
        if (!res.ok) throw new Error("Network response was not ok");
        return res.json();
      })
      .then(data => {
        setList(data);
        setLoading(false);
      })
      .catch(err => {
        console.error("Error fetching data:", err);
        setLoading(false);
      });
  }, []);

  if (loading) return <h2 style={{ textAlign: 'center', marginTop: '50px' }}>Loading Marketplace... 🚀</h2>;

  return (
    <div style={{ padding: '40px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1 style={{ textAlign: 'center', color: '#1e293b', marginBottom: '30px' }}>Student Talent Marketplace 🎓</h1>
      
      {list.length === 0 ? (
        <div style={{ textAlign: 'center', marginTop: '50px' }}>
          <h3>No freelancers found yet. 😔</h3>
          <p>Be the first to join! Go to "Join Us" page.</p>
        </div>
      ) : (
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', 
          gap: '25px' 
        }}>
          {list.map(f => (
            <div key={f._id} style={{ 
              background: 'white', 
              padding: '25px', 
              borderRadius: '15px', 
              boxShadow: '0 10px 20px rgba(0,0,0,0.05)',
              border: '1px solid #f1f5f9'
            }} className="freelancer-card-new">
              <div style={{ 
                width: '50px', height: '50px', background: '#38bdf8', color: 'white', 
                borderRadius: '50%', display: 'flex', alignItems: 'center', 
                justifyContent: 'center', fontSize: '20px', fontWeight: 'bold', marginBottom: '15px'
              }}>
                {f.name ? f.name.charAt(0).toUpperCase() : 'U'}
              </div>
              <h3 style={{ margin: '0 0 10px 0', color: '#1e293b' }}>{f.name}</h3>
              <p style={{ background: '#e0f2fe', color: '#0369a1', display: 'inline-block', padding: '4px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: '600' }}>{f.skill}</p>
              <p style={{ marginTop: '15px', fontWeight: 'bold', fontSize: '18px', color: '#334155' }}>${f.price}/hr</p>
              <button style={{ width: '100%', marginTop: '15px', padding: '10px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer' }}>View Profile</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Marketplace;
